#include <stdio.h>
int main() {
    int T, N, Li, Ri, i, j, cnt, ans;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int possibleThieves[N + 1];
        int count = 0;
        for (i = 1; i <= N; i++) {
            scanf("%d %d", &Li, &Ri);
            cnt = 0; ans = 0;
            for (j = 1; j <= N; j++) {
                if (Li <= j && j <= Ri) {
                    if (j == i) {
                        cnt++;
                    } else {
                        ans++;
                    }
                }
            }
            if (cnt == 1) {
                possibleThieves[count] = i;
                count++;
            }
        }
        printf("%d\n", count);
        for (i = 0; i < count; i++) {
            printf("%d\n", possibleThieves[i]);
        }
    }
    return 0;
}

