        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] possibleThieves = new int[N + 1];
            int count = 0;
            for (int i = 1; i <= N; i++) {
                int Li = scanner.nextInt();
                int Ri = scanner.nextInt();
                int cnt = 0; int ans = 0;
                for (int j = 1; j <= N; j++) {
                    if (Li <= j && j <= Ri) {
                        if (j == i) {
                            cnt++;
                        } else {
                            ans++;
                        }
                    }
                }
                if (cnt == 1) {
                    possibleThieves[count] = i;
                    count++;
                }
            }
            System.out.println(count);
            for (int i = 0; i < count; i++) {
                System.out.println(possibleThieves[i]);
