    let N = parseInt(lines[i++]);
    let possibleThieves = [];
    for (let i = 1; i <= N; i++) {
        let [Li, Ri] = lines[i++].split(' ').map(Number);
        let cnt = 0; let ans = 0;
        for (let j = 1; j <= N; j++) {
            if (Li <= j && j <= Ri) {
                if (j == i) {
                    cnt++;
                } else {
                    ans++;
                }
            }
        }
        if (cnt == 1) {
            possibleThieves.push(i);
        }
    }
    console.log(possibleThieves.length);
    possibleThieves.sort((a, b) => a - b);
    for (let thief of possibleThieves) {
        console.log(thief);
    }
}
